		pd[u][v]=1;pd[v][u]=1;
		val[u][v]=w;val[v][u]=w;
	}
	for(int i=1;i<=n;i++)
	{
		p[i]=i;
	}
	int minn=LLONG_MAX;
	while(next_permutation(p+1,p+n+1))
	{
		memset(vis,0,sizeof(vis));
		int ans=0;
		for(int i=1;i<=n;i++)
		{
			int cnt=0,s=0;
			for(int j=1;j<=n;j++)
